-----               BASE TABLE:  AccountBalance
-----               PRIMARY KEY: ID
------------------------------------------------------------
IF OBJECT_ID('[${flyway:defaultSchema}].[vwAccountBalances]', 'V') IS NOT NULL
    DROP VIEW [${flyway:defaultSchema}].[vwAccountBalances];
GO

CREATE VIEW [${flyway:defaultSchema}].[vwAccountBalances]
AS
SELECT
    a.*,
    MJCompany_CompanyID.[Name] AS [Company],
    mjBizAppsAccountingGLAccount_GLAccountID.[Name] AS [GLAccount],
    mjBizAppsAccountingCurrency_CurrencyCode.[Name] AS [CurrencyCode_Virtual]
FROM
    [${flyway:defaultSchema}].[AccountBalance] AS a
INNER JOIN
    [${mjSchema}].[Company] AS MJCompany_CompanyID
  ON
    [a].[CompanyID] = MJCompany_CompanyID.[ID]
INNER JOIN
    [${flyway:defaultSchema}].[GLAccount] AS mjBizAppsAccountingGLAccount_GLAccountID
  ON
    [a].[GLAccountID] = mjBizAppsAccountingGLAccount_GLAccountID.[ID]
INNER JOIN
    [${flyway:defaultSchema}].[Currency] AS mjBizAppsAccountingCurrency_CurrencyCode
  ON
    [a].[CurrencyCode] = mjBizAppsAccountingCurrency_CurrencyCode.[Code]
GO
