            p.[Depth] + 1 AS [Depth]
        FROM
            [${flyway:defaultSchema}].[DimensionValue] c
        INNER JOIN
            CTE_RootParent p ON c.[ID] = p.[ParentDimensionValueID]
        WHERE
            p.[Depth] < 100
    )
    SELECT TOP 1
        [RootParentID] AS RootID
    FROM
        CTE_RootParent
    WHERE
        [ParentDimensionValueID] IS NULL
    ORDER BY
        [RootParentID]
);
